  return [{ json: { message: '⚠️ No encontramos su información. Por favor contacte a servicio al cliente al teléfono (999) 000-0000.' } }];
}

const adeudo = parseFloat(cliente.importe || 0);
const nombre = cliente.cliente || 'Cliente';

if (adeudo <= 0) {
  return [{ json: { message: `Hola ${nombre} 👋, no tiene adeudos pendientes. ¡Gracias por mantenerse al corriente!` } }];
}

const vencimiento = cliente.fecha_vencimiento || 'N/D';
return [{
  json: {
    message: `Hola ${nombre} 👋\n\nSu adeudo actual es:\n💰 *${adeudo.toFixed(2)} €*\n📅 Vencimiento: ${vencimiento}\n\nPara más información comuníquese con su ejecutivo de cuenta.`
  }
}];

const todos = $input.all();
const busqueda = $('Extraer Categoría').item.json.message.toLowerCase();

const productos = todos.filter(p => 
  p.json.producto && p.json.producto.toLowerCase().includes(busqueda)
);

if (productos.length === 0) {
  return [{ json: { message: '⚠️ No encontramos productos con ese nombre. Intente con otro término o contacte a su ejecutivo.' } }];
}

let respuesta = '📦 *Disponibilidad de productos:*\n\n';

for (const p of productos) {
  const stock = parseInt(p.json.stock_actual || 0);
  const minimo = parseInt(p.json.stock_minimo || 0);
  const nombre = p.json.producto || 'Producto';
  const status = stock > minimo ? '✅ Disponible' : '⚠️ Stock bajo';
  respuesta += `*${nombre}*\n${status} — ${stock} unidades\n\n`;
}

respuesta += 'Para hacer un pedido, contacte a su ejecutivo de cuenta.';

return [{ json: { message: respuesta } }];

return [{
