const items = $input.all();
const resultados = [];

for (const item of items) {
  const data = item.json;
  const hoy = new Date();
  hoy.setHours(0, 0, 0, 0);

  const vencimiento = new Date(data.fecha_vencimiento);
  vencimiento.setHours(0, 0, 0, 0);

  const diffDays = Math.round((hoy - vencimiento) / (1000 * 60 * 60 * 24));

  let nivel = null;
  let estado = data.estado || 'AL DÍA';

  // === NUEVA LÓGICA: Respetar el estado que viene de Sheets ===
  // Si en Google Sheets ya está marcado como MOROSO, mantener nivel 4
  // Si está AL DÍA o PAGADO, NO asignar nivel 4 aunque diffDays sea grande

  if (estado === 'MOROSO') {
    // Cliente ya marcado como moroso en Sheets
    nivel = 4;
  }
  else if (estado === 'AL DÍA' || estado === 'PAGADO' || estado === '') {
    // Cliente al día - no asignar nivel de cobranza
    nivel = null;
  }
  else {
    // Para clientes no morosos, calcular según días de vencimiento
    if (diffDays >= -4 && diffDays <= -2) {
      nivel = 1;
      estado = 'POR VENCER';
    } 
    else if (diffDays >= -1 && diffDays <= 1) {
      nivel = 2;
      estado = 'VENCE HOY';
    } 
    else if (diffDays >= 7 && diffDays <= 10) {
      nivel = 3;
      estado = 'VENCIDA';
    }
    else if (diffDays >= 20 && estado !== 'MOROSO') {
      // Si tiene más de 20 días pero NO está marcado como MOROSO,
      // lo marcamos ahora
      nivel = 4;
      estado = 'MOROSO';
    }
    else {
      nivel = null;
      estado = 'AL DÍA';
    }
  }

  resultados.push({
    json: {
      ...data,
      dias_vencido_calculado: diffDays,
      nivel_asignado: nivel,
      estado: estado
    }
  });
}

// Devolver SOLO los que tienen nivel asignado (excluye AL DÍA)
return resultados.filter(r => r.json.nivel_asignado !== null);

