const items = $input.all();

return items.map(item => {
  const data = item.json;

  // Dividir el nombre completo (viene de Extraer Texto N4)
  const nombreCompleto = data.contacto || '';
  const espacioIndex = nombreCompleto.indexOf(' ');
  const firstname = espacioIndex === -1 ? nombreCompleto : nombreCompleto.substring(0, espacioIndex);
  const lastname = espacioIndex === -1 ? '' : nombreCompleto.substring(espacioIndex + 1);

  // Preparar body para actualizar contacto
  return {
    json: {
      contactId: data.id || data.hs_object_id,
      email: data.email,
      firstname: firstname,
      lastname: lastname,
      company: data.cliente,
      outstanding_balance: String(data.importe || 0)
    }
  };
});
